#!/usr/bin/env bash
# =============================================================================
#  Buzzball.Live — Proxmox LXC Install Script (Interactive)
#  Run on your Proxmox host:
#    bash buzzball_lxc.sh
# =============================================================================
#  Buzzball.Live — Proxmox LXC Install Script (Interactive)
#  Run on your Proxmox host:
#    bash buzzball_lxc.sh
# =============================================================================
set -euo pipefail

YW="\033[33m"; BL="\033[36m"; RD="\033[01;31m"; GN="\033[1;92m"; CL="\033[m"; BOLD="\033[1m"; DIM="\033[2m"
BFR="\\r\\033[K"; HOLD="  "; CM="  ✅"; CROSS="  ❌"
msg_info()  { echo -ne "  ${HOLD} ${YW}$1${CL}"; }
msg_ok()    { echo -e "${BFR}${CM} ${GN}$1${CL}"; }
msg_error() { echo -e "${BFR}${CROSS} ${RD}$1${CL}"; exit 1; }

if ! command -v pveversion &>/dev/null; then
  msg_error "Must be run on a Proxmox VE host."
fi

# ── Helper: prompt with default, showing "(recommended)" ─────────────────
ask() {
  local prompt="$1" default="$2" var="$3" rec="${4:-}"
  local rec_tag=""
  [[ -n "$rec" ]] && rec_tag=" ${GN}← recommended${CL}"
  echo -ne "  ${BL}${prompt}${CL} [${BOLD}${default}${CL}]${rec_tag}: "
  read -r input
  eval "$var=\"${input:-$default}\""
}

ask_menu() {
  # Usage: ask_menu "Prompt" VAR REC_INDEX "opt1" "opt2" ...
  local prompt="$1" var="$2" rec_idx="$3"
  shift 3
  local options=("$@")
  echo -e "  ${BL}${prompt}${CL}"
  for i in "${!options[@]}"; do
    local tag=""
    [[ "$((i+1))" == "$rec_idx" ]] && tag="  ${GN}← recommended${CL}"
    echo -e "    ${YW}$((i+1))${CL}) ${options[$i]}${tag}"
  done
  while true; do
    echo -ne "  Choice [${BOLD}${rec_idx}${CL}]: "
    read -r choice
    choice="${choice:-$rec_idx}"
    if [[ "$choice" =~ ^[0-9]+$ ]] && (( choice >= 1 && choice <= ${#options[@]} )); then
      eval "$var=\"${options[$((choice-1))]}\""
      break
    fi
    echo -e "  ${RD}Invalid choice. Enter 1-${#options[@]}.${CL}"
  done
}

clear
echo -e "\n${BL}${BOLD}  ⚾  Buzzball.Live — LXC Installer${CL}\n"
echo -e "  ${DIM}Press Enter to accept the recommended value shown in [brackets].${CL}\n"

# ── Container ID ───────────────────────────────────────────────────────────
NEXT_ID=$(pvesh get /cluster/nextid 2>/dev/null || echo "200")
ask "Container ID" "$NEXT_ID" CTID "rec"

# ── Hostname ───────────────────────────────────────────────────────────────
ask "Hostname" "buzzball" HOSTNAME "rec"

# ── Root password ──────────────────────────────────────────────────────────
ask "Root password" "buzzball" PASSWORD

# ── Storage ───────────────────────────────────────────────────────────────
echo ""
echo -e "  ${BL}Available storage pools:${CL}"

# Collect all active storage pools with their type
declare -a STORAGE_LIST
declare -a STORAGE_TYPE_LIST
while IFS= read -r line; do
  name=$(echo "$line" | awk '{print $1}')
  type=$(echo "$line" | awk '{print $2}')
  status=$(echo "$line" | awk '{print $3}')
  [[ "$status" == "active" ]] || continue
  STORAGE_LIST+=("$name")
  STORAGE_TYPE_LIST+=("$type")
done < <(pvesm status 2>/dev/null | awk 'NR>1')

if [[ ${#STORAGE_LIST[@]} -eq 0 ]]; then
  STORAGE_LIST=("local-lvm" "local")
  STORAGE_TYPE_LIST=("lvm-thin" "dir")
fi

# Determine recommended storage (prefer local-lvm, then zfs, then first active)
REC_STORAGE=1
for i in "${!STORAGE_LIST[@]}"; do
  if [[ "${STORAGE_LIST[$i]}" == "local-lvm" ]]; then
    REC_STORAGE=$((i+1)); break
  fi
done
if [[ $REC_STORAGE -eq 1 ]]; then
  for i in "${!STORAGE_LIST[@]}"; do
    if [[ "${STORAGE_TYPE_LIST[$i]}" == "zfspool" ]]; then
      REC_STORAGE=$((i+1)); break
    fi
  done
fi

for i in "${!STORAGE_LIST[@]}"; do
  rec_tag=""
  [[ "$((i+1))" == "$REC_STORAGE" ]] && rec_tag="  ${GN}← recommended${CL}"
  echo -e "    ${YW}$((i+1))${CL}) ${BOLD}${STORAGE_LIST[$i]}${CL}  ${DIM}(${STORAGE_TYPE_LIST[$i]})${CL}${rec_tag}"
done
echo -ne "  Choice [${BOLD}${REC_STORAGE}${CL}] (or type a name): "
read -r STORAGE_INPUT
if [[ -z "$STORAGE_INPUT" ]]; then
  STORAGE="${STORAGE_LIST[$((REC_STORAGE-1))]}"
elif [[ "$STORAGE_INPUT" =~ ^[0-9]+$ ]]; then
  STORAGE="${STORAGE_LIST[$((STORAGE_INPUT-1))]:-${STORAGE_LIST[$((REC_STORAGE-1))]}}"
else
  STORAGE="$STORAGE_INPUT"
fi

# ── Disk size ──────────────────────────────────────────────────────────────
ask "Disk size (GB)" "4" DISK "rec"

# ── Memory ────────────────────────────────────────────────────────────────
echo ""
ask_menu "Memory allocation:" MEMORY_RAW "2" \
  "256 MB  (minimal)" \
  "512 MB  (recommended)" \
  "1024 MB (comfortable)" \
  "2048 MB (generous)" \
  "Custom"
case "$MEMORY_RAW" in
  "256 MB"*)  MEMORY=256 ;;
  "512 MB"*)  MEMORY=512 ;;
  "1024 MB"*) MEMORY=1024 ;;
  "2048 MB"*) MEMORY=2048 ;;
  "Custom")   ask "Memory in MB" "512" MEMORY "rec" ;;
esac

# ── CPU cores ─────────────────────────────────────────────────────────────
ask "CPU cores" "1" CORES "rec"

# ── Network bridge ────────────────────────────────────────────────────────
echo ""
echo -e "  ${BL}Available network bridges:${CL}"
mapfile -t BRIDGE_LIST < <(ip link show 2>/dev/null | awk -F': ' '/^[0-9]+: vmbr/{print $2}' | awk '{print $1}')
if [[ ${#BRIDGE_LIST[@]} -eq 0 ]]; then
  BRIDGE_LIST=("vmbr0")
fi

for i in "${!BRIDGE_LIST[@]}"; do
  local_tag=""
  [[ $i -eq 0 ]] && local_tag="  ${GN}← recommended${CL}"
  echo -e "    ${YW}$((i+1))${CL}) ${BRIDGE_LIST[$i]}${local_tag}"
done
echo -ne "  Choice [${BOLD}1${CL}] (or type a name): "
read -r BRIDGE_INPUT
if [[ -z "$BRIDGE_INPUT" ]]; then
  BRIDGE="${BRIDGE_LIST[0]}"
elif [[ "$BRIDGE_INPUT" =~ ^[0-9]+$ ]]; then
  BRIDGE="${BRIDGE_LIST[$((BRIDGE_INPUT-1))]:-${BRIDGE_LIST[0]}}"
else
  BRIDGE="$BRIDGE_INPUT"
fi

# ── IP configuration ──────────────────────────────────────────────────────
echo ""
ask_menu "IP configuration:" IP_MODE "1" \
  "DHCP (automatic, recommended)" \
  "Static IP"

if [[ "$IP_MODE" == "Static IP" ]]; then
  ask "IP address (CIDR, e.g. 192.168.1.100/24)" "" STATIC_IP
  ask "Gateway" "" STATIC_GW
  ask "DNS server" "1.1.1.1" STATIC_DNS "rec"
  NET_CONFIG="ip=${STATIC_IP},gw=${STATIC_GW}"
  DNS_CONFIG="--nameserver ${STATIC_DNS}"
else
  NET_CONFIG="ip=dhcp"
  DNS_CONFIG=""
fi

# ── Unprivileged ───────────────────────────────────────────────────────────
echo ""
ask_menu "Container type:" PRIV_MODE "1" \
  "Unprivileged (recommended — more secure)" \
  "Privileged (full host access)"
[[ "$PRIV_MODE" == "Unprivileged"* ]] && UNPRIVILEGED=1 || UNPRIVILEGED=0

# ── Auto-start on boot ─────────────────────────────────────────────────────
ask_menu "Start on Proxmox boot:" ONBOOT_MODE "1" \
  "Yes (recommended)" \
  "No"
[[ "$ONBOOT_MODE" == "Yes"* ]] && ONBOOT=1 || ONBOOT=0

# ── Template ──────────────────────────────────────────────────────────────
# Check if any debian-12 template is already cached locally
TEMPLATE=$(ls /var/lib/vz/template/cache/debian-12-standard_*.tar.zst 2>/dev/null \
  | sort -V | tail -1 | xargs -r basename)

# If not cached, find latest available from Proxmox repo
if [[ -z "$TEMPLATE" ]]; then
  msg_info "Checking available Debian 12 templates"
  pveam update &>/dev/null
  TEMPLATE=$(pveam available --section system 2>/dev/null \
    | awk '/debian-12-standard/{print $2}' \
    | sort -V | tail -1)
  msg_ok "Found template: $TEMPLATE"
fi

if [[ -z "$TEMPLATE" ]]; then
  msg_error "Could not find a Debian 12 template. Run 'pveam update' and try again."
fi

# ── Summary ───────────────────────────────────────────────────────────────
echo ""
echo -e "  ${BL}${BOLD}┌──────────────────────────────────────────┐${CL}"
echo -e "  ${BL}${BOLD}│         Configuration Summary            │${CL}"
echo -e "  ${BL}${BOLD}├──────────────────────────────────────────┤${CL}"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Container ID:"  "$CTID"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Hostname:"      "$HOSTNAME"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Storage:"       "$STORAGE"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Disk:"          "${DISK}GB"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Memory:"        "${MEMORY}MB"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "CPU Cores:"     "$CORES"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Bridge:"        "$BRIDGE"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Network:"       "$NET_CONFIG"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Type:"          "$([ $UNPRIVILEGED -eq 1 ] && echo Unprivileged || echo Privileged)"
printf "  ${BL}│${CL}  %-18s ${BOLD}%-22s${CL}${BL}│${CL}\n" "Start on boot:" "$([ $ONBOOT -eq 1 ] && echo Yes || echo No)"
echo -e "  ${BL}${BOLD}└──────────────────────────────────────────┘${CL}"
echo ""
echo -e "  ${DIM}Tip: just mash Enter through all prompts to use all recommended settings.${CL}"
echo ""
read -r -p "  Proceed with installation? [y/N] " YN
[[ "${YN,,}" == "y" ]] || { echo "Aborted."; exit 0; }

# ── Template ──────────────────────────────────────────────────────────────
TPATH="/var/lib/vz/template/cache/${TEMPLATE}"
if [[ ! -f "$TPATH" ]]; then
  msg_info "Downloading template: $TEMPLATE"
  pveam download local "$TEMPLATE" &>/dev/null || msg_error "Template download failed — run 'pveam update' on your host and try again"
  msg_ok "Downloaded $TEMPLATE"
else
  msg_ok "Template already cached: $TEMPLATE"
fi

# ── Create LXC ────────────────────────────────────────────────────────────
msg_info "Creating container ${CTID}"
pct create "$CTID" "$TPATH" \
  --hostname "$HOSTNAME" --password "$PASSWORD" \
  --storage "$STORAGE" --rootfs "${STORAGE}:${DISK}" \
  --memory "$MEMORY" --cores "$CORES" \
  --net0 "name=eth0,bridge=${BRIDGE},${NET_CONFIG}" \
  ${DNS_CONFIG} \
  --unprivileged "$UNPRIVILEGED" --features nesting=1 \
  --onboot "$ONBOOT" --start 0 &>/dev/null \
  || msg_error "Failed to create container"
msg_ok "Created container ${CTID}"

msg_info "Starting container"
pct start "$CTID" &>/dev/null
sleep 8
msg_ok "Container started"

# ── Install packages ──────────────────────────────────────────────────────
msg_info "Installing nginx and Node.js"
pct exec "$CTID" -- bash -c "
  export DEBIAN_FRONTEND=noninteractive
  apt-get update -qq 2>&1 | tail -1
  apt-get install -y -qq curl gnupg2 nginx python3 2>&1 | tail -1
  curl -fsSL https://deb.nodesource.com/setup_20.x | bash - &>/dev/null
  apt-get install -y -qq nodejs 2>&1 | tail -1
" || msg_error "Package install failed"
msg_ok "Installed nginx + Node.js 20"

# ── Deploy app ────────────────────────────────────────────────────────────
msg_info "Deploying Buzzball web app"
pct exec "$CTID" -- mkdir -p /opt/buzzball
HTML_B64=""
echo "$HTML_B64" | pct exec "$CTID" -- bash -c "base64 -d > /opt/buzzball/index.html"
msg_ok "Deployed Buzzball web app"

# ── Configure nginx ───────────────────────────────────────────────────────
msg_info "Configuring nginx"
pct exec "$CTID" -- bash -c '
cat > /etc/nginx/sites-available/buzzball <<EOF
server {
    listen 80 default_server;
    listen [::]:80 default_server;
    root /opt/buzzball;
    index index.html;
    server_name _;
    location / { try_files $uri $uri/ /index.html; }
    location /health { return 200 "OK"; add_header Content-Type text/plain; }
}
EOF
ln -sf /etc/nginx/sites-available/buzzball /etc/nginx/sites-enabled/buzzball
rm -f /etc/nginx/sites-enabled/default
nginx -t &>/dev/null && systemctl enable nginx &>/dev/null && systemctl restart nginx
'
msg_ok "nginx running"

# ── Management scripts ────────────────────────────────────────────────────
msg_info "Installing management tools"
pct exec "$CTID" -- bash -c '
cat > /usr/local/bin/buzzball-status <<EOF
#!/bin/bash
echo "=== Buzzball Status ==="
printf "nginx:    "; systemctl is-active nginx
printf "app:      "; ls /opt/buzzball/index.html &>/dev/null && echo present || echo MISSING
echo "URLs:"
hostname -I | tr " " "\n" | grep -v "^$" | sed "s|^|  http://|"
EOF
chmod +x /usr/local/bin/buzzball-status

cat > /usr/local/bin/buzzball-update <<EOF
#!/bin/bash
echo "Pulling latest from GitHub Pages..."
curl -fsSL https://badger-fi.github.io/buzzball/index.html -o /opt/buzzball/index.html \
  && echo "Updated." || echo "Failed."
systemctl reload nginx
EOF
chmod +x /usr/local/bin/buzzball-update

(crontab -l 2>/dev/null; echo "0 6 * * * /usr/local/bin/buzzball-update >> /var/log/buzzball-update.log 2>&1") | crontab -
'
msg_ok "Management tools installed"

# ── Done ──────────────────────────────────────────────────────────────────
IP=$(pct exec "$CTID" -- hostname -I 2>/dev/null | awk '{print $1}')
[[ -z "$IP" ]] && IP="${STATIC_IP%%/*}" 2>/dev/null || true

echo ""
echo -e "${GN}${BOLD}"
echo "  ╔══════════════════════════════════════════════╗"
echo "  ║        Buzzball.Live is ready! ⚾             ║"
echo "  ╠══════════════════════════════════════════════╣"
echo "  ║                                              ║"
printf "  ║  App  →  ${BL}http://%-28s${GN}║\n" "${IP}"
printf "  ║  CTID →  %-32s║\n" "${CTID}"
printf "  ║  Host →  %-32s║\n" "${HOSTNAME}"
printf "  ║  Pass →  %-32s║\n" "${PASSWORD}"
echo "  ║                                              ║"
echo "  ║  pct enter ${CTID}        shell into container  ║"
echo "  ║  buzzball-status       check everything      ║"
echo "  ║  buzzball-update       pull latest app       ║"
echo "  ╚══════════════════════════════════════════════╝"
echo -e "${CL}"
